import{_ as i,o as a,c as o,a3 as t}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Web.Api","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/web-api.md","filePath":"cosmos/framework/packages/web-api.md","lastUpdated":1783216089000}'),n={name:"cosmos/framework/packages/web-api.md"};function d(l,e,r,s,c,p){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="xihan-framework-web-api" tabindex="-1">XiHan.Framework.Web.Api <a class="header-anchor" href="#xihan-framework-web-api" aria-label="Permalink to &quot;XiHan.Framework.Web.Api&quot;">​</a></h1><blockquote><p>动态 API：把应用服务自动暴露为 REST 接口，并装配一整条 Web 中间件管道（转发头、追踪、文化、异常/请求/API 日志、限流、熔断、CORS、鉴权、租户解析、OpenAPI 安全）。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Web.Api</code></li><li><strong>模块类</strong>：<code>XiHanWebApiModule</code></li><li><strong>所在层</strong>：Web 层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Web.Api 是构建 HTTP 后端的主力包。两件核心事：一是<strong>动态 API</strong>——你只写继承 <code>IApplicationService</code> 且标注 <code>[DynamicApi]</code> 的应用服务，框架在启动时自动为它们生成控制器与路由，你无需手写 Controller；二是<strong>中间件管道</strong>——模块在 <code>OnApplicationInitialization</code> 里按固定顺序装配好一整套 Web 中间件，开箱即用地处理转发头、追踪 ID、请求文化、日志、限流、熔断、CORS、认证、多租户解析、授权与端点映射。</p><p>新手可以把它理解为：引用它 + 写应用服务 = 一个带日志、鉴权、多租户、统一响应的 REST API。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>想把应用服务（<code>AppService</code>）直接变成 REST 接口，不想手写控制器与路由。</li><li>需要一套现成的 Web 管道：统一异常/请求/API 访问日志、TraceId、请求文化、CORS、JWT 认证、授权、多租户解析。</li><li>需要入站保护：可按配置开启限流（RateLimiter）与熔断（CircuitBreaking）。</li><li>需要反向代理（nginx/网关）后还原真实 scheme/host/客户端 IP（<code>UseForwardedHeaders</code>）。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Web.Api</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanWebApiModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>动态 API 发现与注册</strong>：扫描已加载程序集，找出实现 <code>IApplicationService</code> 的类型，为标注 <code>[DynamicApi]</code>（定义在 <a href="./application">Application</a> 包）的服务生成动态控制器。默认约定「剥离动词」路由（如 <code>CreateXxxAsync</code> → <code>POST /Xxx</code>）、Pascal 命名、<code>api</code> 前缀。</li><li><strong>完整中间件管道</strong>：在应用初始化时一次性装配（见下）。</li><li><strong>统一响应与模型校验</strong>：<code>XiHanApiResponseResultFilter</code> 统一包装响应；模型校验失败返回 400 并把错误放入 <code>Data</code>。</li><li><strong>JWT 认证 + 授权</strong>：按 <code>XiHan:Authentication:Jwt</code> 配置装配 JWT Bearer；支持从 query string 的 <code>access_token</code> 提取（SignalR 场景）；可要求全局登录（<code>RequireAuthenticatedUser</code>）。</li><li><strong>CORS</strong>：<code>XiHan:Web:Api:Cors</code> 配置来源/方法/头/凭据/预检缓存。</li><li><strong>多租户解析</strong>：<code>XiHanTenantResolveMiddleware</code> + Header/QueryString 两个租户贡献者。</li><li><strong>OpenAPI 安全</strong>：<code>XiHanOpenApiSecurityMiddleware</code> 对开放接口做签名、内容签名、加密与防重放校验。</li><li><strong>异步日志</strong>：访问/操作/异常/API/登录五类日志经内存队列 + 后台 Worker 异步落库（默认 Null 写入器，由上层应用覆盖）。</li></ul><h2 id="中间件管道顺序-onapplicationinitialization" tabindex="-1">中间件管道顺序（<code>OnApplicationInitialization</code>） <a class="header-anchor" href="#中间件管道顺序-onapplicationinitialization" aria-label="Permalink to &quot;中间件管道顺序（`OnApplicationInitialization`）&quot;">​</a></h2><p>框架按下列固定顺序装配（部分按配置开关）：</p><ol><li><code>UseForwardedHeaders</code>（反代转发头还原，必须最前）</li><li><code>XiHanTraceIdMiddleware</code>（TraceId）</li><li><code>UseXiHanRequestCulture</code>（请求文化）</li><li><code>XiHanRequestContextMiddleware</code>（请求上下文）</li><li><code>XiHanExceptionLoggingMiddleware</code>（异常日志）</li><li><code>XiHanRequestLoggingMiddleware</code>（请求日志）</li><li><code>UseRouting</code></li><li><code>UseRateLimiter</code>（当 <code>XiHan:Web:RateLimiting:IsEnabled=true</code>）</li><li><code>XiHanCircuitBreakingMiddleware</code>（当 <code>XiHan:Web:CircuitBreaking:IsEnabled=true</code>）</li><li><code>UseCors</code></li><li>本地对象存储静态文件（<code>XiHan:ObjectStorage:Local</code>，匿名直链）</li><li><code>XiHanApiLoggingMiddleware</code>（API 访问日志）</li><li><code>XiHanOpenApiSecurityMiddleware</code>（OpenAPI 安全）</li><li><code>UseAuthentication</code></li><li><code>XiHanTenantResolveMiddleware</code>（租户解析）</li><li><code>UseAuthorization</code></li><li><code>UseEndpoints</code>：<code>MapControllers()</code> + <code>MapOpenApi().AllowAnonymous()</code></li></ol><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHanWebApiModule</code></td><td>模块类，装配服务与整条中间件管道</td></tr><tr><td><code>[DynamicApi]</code>（Application 包）</td><td>标注应用服务/方法以生成动态 API</td></tr><tr><td><code>DynamicApiControllerFeatureProvider</code> / <code>DefaultDynamicApiConvention</code></td><td>动态控制器发现与路由约定</td></tr><tr><td><code>DynamicApiOptions</code></td><td>动态 API 开关、路由前缀、命名与批量选项</td></tr><tr><td><code>XiHanCorsOptions</code> / <code>XiHanWebAuthOptions</code></td><td>CORS 与认证/授权配置</td></tr><tr><td><code>XiHanRateLimitingOptions</code> / <code>XiHanCircuitBreakingOptions</code></td><td>限流与熔断配置（<code>XiHan:Web:RateLimiting</code>、<code>XiHan:Web:CircuitBreaking</code>）</td></tr><tr><td><code>XiHanOpenApiSecurityOptions</code></td><td>OpenAPI 签名/加密/防重放安全配置</td></tr><tr><td><code>XiHanController</code></td><td>控制器基类</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：<a href="./web-core">XiHan.Framework.Web.Core</a>、<a href="./application">XiHan.Framework.Application</a>、<a href="./multitenancy">XiHan.Framework.MultiTenancy</a>、<a href="./serialization">XiHan.Framework.Serialization</a>、<a href="./localization">XiHan.Framework.Localization</a>、<a href="./logging">XiHan.Framework.Logging</a>。</li><li>第三方核心：<code>Microsoft.AspNetCore.OpenApi</code>（OpenAPI 文档生成）。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./web-docs">XiHan.Framework.Web.Docs</a> — 在动态 API 之上提供 Scalar/Swagger UI 文档界面。</li><li><a href="./../concepts/dynamic-api">动态 API</a> — 动态 API 的设计与约定说明。</li><li><a href="./../concepts/lifecycle">模块生命周期</a> — <code>ConfigureServices</code>/<code>OnApplicationInitialization</code> 等生命周期钩子。</li></ul>',23)])])}const g=i(n,[["render",d]]);export{k as __pageData,g as default};
